        packet.append(UInt8((crc >> 8) & 0xFF))         // CRC 高字节
        packet.append(UInt8(dataLen & 0xFF))            // DataLen 低字节
        packet.append(UInt8((dataLen >> 8) & 0xFF))      // DataLen 高字节
        packet.append(content)

        return packet
    }
}

