39	                        .font(.caption)
40	                    }
41	                }
42	            }
43	
44	            // Model Section
45	            Section("Whisper 模型") {
46	                ForEach(WhisperModel.allCases) { model in
47	                    ModelRow(
48	                        model: model,
49	                        isSelected: appState.selectedModel == model,
50	                        isSwitching: isSwitching,
51	                        modelManager: modelManager
52	                    ) {
53	                        guard !isSwitching else { return }
54	                        appState.selectedModel = model
55	                    }
56	                }
57	
58	                Text("模型存储位置：~/Library/Application Support/VoicePepper/models/")
59	                    .font(.caption2)
60	                    .foregroundColor(.secondary)
61	            }
62	
63	            // VAD Section
64	            Section("转录敏感度") {
65	                HStack {
66	                    Text("静音检测阈值")
67	                    Spacer()
68	                    Stepper("\(appState.vadSilenceThresholdMs) ms",
69	                            value: $appState.vadSilenceThresholdMs,
70	                            in: 200...2000,
71	                            step: 100)
72	                }
73	                Text("值越小，分段越频繁；值越大，段落越长")
74	                    .font(.caption)
75	                    .foregroundColor(.secondary)
76	            }
77	        }
78	        .formStyle(.grouped)
79	        .padding()
80	        .frame(width: 520, height: 480)
81	    }
82	
83	    /// 任意模型正在下载或加载时为 true，此时禁止切换
84	    private var isSwitching: Bool {
85	        modelManager.modelStates.values.contains {
86	            if case .downloading = $0 { return true }
87	            if case .loading = $0 { return true }
88	            return false
89	        }
90	    }
91	
92	    private func openAccessibilitySettings() {
93	        let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility")!
94	        NSWorkspace.shared.open(url)
95	    }
96	}
