98	// MARK: - Model Row
99	
100	private struct ModelRow: View {
101	    let model: WhisperModel
102	    let isSelected: Bool
103	    let isSwitching: Bool
104	    let modelManager: WhisperModelManager
105	    let onSelect: () -> Void
106	
107	    var body: some View {
108	        Button(action: onSelect) {
109	            HStack(spacing: 10) {
110	                // 选中指示
111	                Image(systemName: isSelected ? "largecircle.fill.circle" : "circle")
112	                    .foregroundColor(isSelected ? .accentColor : .secondary)
113	                    .frame(width: 16)
114	
115	                // 模型名称 + 推荐标签
116	                VStack(alignment: .leading, spacing: 2) {
117	                    HStack(spacing: 6) {
118	                        Text(model.displayName)
119	                            .fontWeight(isSelected ? .semibold : .regular)
120	
121	                        if model.isRecommended {
122	                            Text("推荐")
123	                                .font(.caption2)
124	                                .fontWeight(.medium)
125	                                .padding(.horizontal, 5)
126	                                .padding(.vertical, 2)
127	                                .background(Color.yellow.opacity(0.25))
128	                                .foregroundColor(.orange)
129	                                .cornerRadius(4)
130	                        }
131	                    }
132	
133	                    statusSubtitle
134	                }
135	
136	                Spacer()
137	
138	                statusTrailing
139	            }
140	            .contentShape(Rectangle())
141	        }
142	        .buttonStyle(.plain)
143	        .disabled(isSwitching && !isSelected)
144	        .opacity(isSwitching && !isSelected ? 0.45 : 1.0)
145	    }
146	
147	    @ViewBuilder
148	    private var statusSubtitle: some View {
149	        switch resolvedState {
150	        case .downloading(let progress):
151	            VStack(alignment: .leading, spacing: 3) {
152	                ProgressView(value: progress)
153	                    .frame(width: 160)
154	                Text(String(format: "下载中 %.0f%%", progress * 100))
155	                    .font(.caption)
156	                    .foregroundColor(.secondary)
157	            }
158	        case .loading:
159	            Text("加载中…")
160	                .font(.caption)
161	                .foregroundColor(.secondary)
162	        case .failed:
163	            Text("下载失败，请检查网络连接")
164	                .font(.caption)
165	                .foregroundColor(.red)
166	        case .ready:
167	            if modelManager.activeModel == model {
168	                Text("使用中")
169	                    .font(.caption)
170	                    .foregroundColor(.green)
171	            } else {
172	                Text("已下载")
173	                    .font(.caption)
174	                    .foregroundColor(.secondary)
175	            }
176	        default:
177	            // idle / nil — check local file
178	            if modelManager.isModelDownloaded(model) {
179	                Text("已下载")
180	                    .font(.caption)
