private var bleStatusIndicator: some View {
    HStack(spacing: 4) {
        // 连接状态圆点
        Circle()
            .fill(bleConnectionColor)
            .frame(width: 8, height: 8)

        Text(bleConnectionText)
            .font(.caption2)
            .foregroundColor(.secondary)

