            Divider().frame(height: 12)
            if battery == 110 {
                Image(systemName: "battery.100.bolt")
                    .font(.caption2)
                    .foregroundColor(.green)
            } else {
                Image(systemName: batteryIcon(battery))
                    .font(.caption2)
                    .foregroundColor(battery <= 20 ? .red : .secondary)
