    products: [
        .executable(name: "VoicePepper", targets: ["VoicePepper"]),
    ],
    dependencies: [
        // Global hotkey management - pinned to avoid #Preview macro issues with CLI tools
        .package(
            url: "https://github.com/sindresorhus/KeyboardShortcuts",
            exact: "1.14.0"
        ),
    ],
    targets: [
